// ── Main ─────────────────────────────────────────────────────────────────
const data = JSON.parse(readFileSync(expPath, "utf8"));

function addTo(key, newItems) {
  if (!data[key]) data[key] = [];
  const ids = new Set(data[key].map(q => q.id));
  let added = 0;
  for (const q of newItems) {
    if (!ids.has(q.id)) { data[key].push(q); ids.add(q.id); added++; }
  }
  return added;
}

const results = {
  sentenceCompletion: addTo("sentenceCompletion", scExtra),
  paraphrasing: addTo("paraphrasing", paraExtra),
  grammar: addTo("grammar", grammarExtra),
  wordFormation: addTo("wordFormation", wfExtra),
  reading: addTo("reading", readingExtra),
  lectureQuestions: addTo("lectureQuestions", lectureExtra),
  textCompletion: addTo("textCompletion", tcExtra),
  writingTask: addTo("writingTask", writingExtra),
};

writeFileSync(expPath, JSON.stringify(data, null, 2), "utf8");
for (const [k, n] of Object.entries(results)) {
  console.log(`  ${k}: +${n} (total: ${data[k].length})`);
}
console.log("\nDone.");
